  const [userId, setUserId] = useState('user-123');
  const [action, setAction] = useState('create-note');
  const [tokenLength, setTokenLength] = useState(String(DEFAULT_TOKEN_LENGTH));
  const [ttlMinutes, setTtlMinutes] = useState('30');
  const [tokens, setTokens] = useState([]);
  const appState = useRef(AppState.currentState);

  useEffect(() => {
    const sub = AppState.addEventListener('change', (nextState) => {
      appState.current = nextState;
    });
    return () => sub.remove();
  }, []);

  const generateToken = useCallback(() => {
    const length = Math.max(8, parseInt(tokenLength, 10) || DEFAULT_TOKEN_LENGTH);
    const ttlMs = Math.max(1, parseInt(ttlMinutes, 10) || 30) * 60 * 1000;

    const newToken = createOfflineSessionToken({
      userId: userId.trim() || 'anonymous',
      action: action.trim() || 'offline-session',
      length,
      ttlMs,
    });

    setTokens((prev) => [newToken, ...prev]);
    return newToken;
  }, [action, tokenLength, ttlMinutes, userId]);

  const trackOfflineAction = useCallback(() => {
    if (!isOnline) {
      generateToken();
    }
  }, [generateToken, isOnline]);

  const expireToken = useCallback((id) => {
    setTokens((prev) =>
      prev.map((item) =>
        item.id === id ? { ...item, expiresAt: Date.now() - 1 } : item
      )
    );
  }, []);

  const clearExpired = useCallback(() => {
    setTokens((prev) => prev.filter((item) => !isTokenExpired(item)));
  }, []);

